/**
 * Navbar Component
 * Accessible navigation bar optimized for all ages
 */

import React, { useState } from "react";
import { Heart, Menu, X } from "lucide-react";

const Navbar = ({ onLoginClick }) => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  return (
    <nav className="bg-white/95 backdrop-blur-md shadow-sm sticky top-0 z-50 border-b border-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">
          {/* Logo */}
          <div className="flex items-center space-x-3">
            <div className="w-11 h-11 bg-gradient-to-br from-teal-500 to-teal-600 rounded-xl flex items-center justify-center">
              <Heart className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl sm:text-3xl font-bold text-gray-900">
              Pulse.ai
            </span>
          </div>

          {/* Desktop Navigation - Larger text for readability */}
          <div className="hidden md:flex items-center space-x-8 lg:space-x-10">
            <a
              href="#features"
              className="text-lg font-medium text-gray-700 hover:text-teal-600 transition-colors py-2"
            >
              Features
            </a>
            <a
              href="#how-it-works"
              className="text-lg font-medium text-gray-700 hover:text-teal-600 transition-colors py-2"
            >
              How it Works
            </a>
            <a
              href="#about"
              className="text-lg font-medium text-gray-700 hover:text-teal-600 transition-colors py-2"
            >
              About
            </a>
            <button
              onClick={onLoginClick}
              className="bg-gradient-to-r from-teal-600 to-teal-700 text-white px-8 py-3 rounded-xl hover:from-teal-700 hover:to-teal-800 transition-all text-lg font-semibold shadow-lg shadow-teal-500/25 hover:shadow-xl"
            >
              Login
            </button>
          </div>

          {/* Mobile Menu Button - Larger touch target */}
          <button
            className="md:hidden p-3 rounded-xl hover:bg-gray-100 transition-colors"
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            aria-label={mobileMenuOpen ? "Close menu" : "Open menu"}
          >
            {mobileMenuOpen ? (
              <X className="w-7 h-7 text-gray-700" />
            ) : (
              <Menu className="w-7 h-7 text-gray-700" />
            )}
          </button>
        </div>

        {/* Mobile Menu - Larger text and touch targets */}
        {mobileMenuOpen && (
          <div className="md:hidden pb-6 pt-2 space-y-2 border-t border-gray-100">
            <a
              href="#features"
              className="block text-lg font-medium text-gray-700 hover:text-teal-600 hover:bg-teal-50 rounded-xl px-4 py-4 transition-all"
              onClick={() => setMobileMenuOpen(false)}
            >
              Features
            </a>
            <a
              href="#how-it-works"
              className="block text-lg font-medium text-gray-700 hover:text-teal-600 hover:bg-teal-50 rounded-xl px-4 py-4 transition-all"
              onClick={() => setMobileMenuOpen(false)}
            >
              How it Works
            </a>
            <a
              href="#about"
              className="block text-lg font-medium text-gray-700 hover:text-teal-600 hover:bg-teal-50 rounded-xl px-4 py-4 transition-all"
              onClick={() => setMobileMenuOpen(false)}
            >
              About
            </a>
            <button
              onClick={() => {
                onLoginClick();
                setMobileMenuOpen(false);
              }}
              className="w-full bg-gradient-to-r from-teal-600 to-teal-700 text-white px-6 py-4 rounded-xl hover:from-teal-700 hover:to-teal-800 transition-all text-lg font-semibold mt-2"
            >
              Login
            </button>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
